package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Text   template.HTML
}

func main() {
	http.HandleFunc("/comments", func(w http.ResponseWriter, r *http.Request) {
		// Sample comments data
		comments := []Comment{
			{Author: "Alice", Text: template.HTML("Hello, this is a <b>bold</b> comment.")},
			{Author: "Bob", Text: template.HTML("This comment has an <i>italic</i> text.")},
			{Author: "Charlie", Text: template.HTML("Check out this <a href='#'>link</a>.")},
		}

		tmpl := template.Must(template.ParseFiles("comments.html"))
		if err := tmpl.Execute(w, comments); err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		}
	})

	http.ListenAndServe(":8080", nil)
}